    ```java
public int countRodsWithAllColors(String rings) {
    int[] rod_colors = new int[10];

    for (int i = 0; i < rings.length(); i += 2) {
        int color = rings.charAt(i) - 'A';
        int rod = rings.charAt(i + 1) - '0';

        rod_colors[rod] |= (1 << color);
    }

    int count = 0;
    for (int colors : rod_colors) {
        if (colors == 7) { 
            count++;
        }
    }

    return count;
}
```

